	if hostname == "" {
		ctx.Error("URL must contain a valid hostname", fasthttp.StatusBadRequest)
		return
	}

	// SSRF protection: validate the host doesn't resolve to a private IP
	if err := validateHost(hostname); err != nil {
		ctx.Error("URL not allowed: "+err.Error(), fasthttp.StatusBadRequest)
		return
	}

	// Use fasthttp.Client with safe dialer to prevent SSRF via redirects
	client := &fasthttp.Client{
		Dial:                safeDial,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		MaxResponseBodySize: maxResponseBodySize,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 5
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		ctx.Error("Failed to fetch URL", fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Check content type - only parse HTML
	contentType := string(res.Header.ContentType())
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.Error("Response is not HTML", fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error("Failed to parse HTML", fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	inTitle := false

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			err := tokenizer.Err()
			if err == io.EOF {
				return title, description, nil
			}
			return title, description, err

		case html.StartTagToken, html.SelfClosingTagToken:
			tn, hasAttr := tokenizer.TagName()
			tagName := string(tn)

			if tagName == "title" && tt == html.StartTagToken {
				inTitle = true
			}

			if tagName == "meta" && hasAttr {
				var nameVal, contentVal string
				for {
					key, val, more := tokenizer.TagAttr()
					k := strings.ToLower(string(key))
					if k == "name" {
						nameVal = strings.ToLower(string(val))
					} else if k == "content" {
						contentVal = string(val)
					}
					if !more {
						break
					}
				}
				if nameVal == "description" && description == "" {
					description = contentVal
				}
			}

		case html.TextToken:
			if inTitle && title == "" {
				title = strings.TrimSpace(string(tokenizer.Text()))
			}

		case html.EndTagToken:
			tn, _ := tokenizer.TagName()
			if string(tn) == "title" {
				inTitle = false
			}
			// Stop parsing after </head> for efficiency
			if string(tn) == "head" {
				return title, description, nil
			}
		}
	}
}

func main() {
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not found", fasthttp.StatusNotFound)
		}
	}

	fmt.Println("Server starting on :8080")
	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

