// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// Check loopback
	if ip.IsLoopback() {
		return true
	}

	// Check unspecified (0.0.0.0 or ::)
	if ip.IsUnspecified() {
		return true
	}

	// Check link-local
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check multicast
	if ip.IsMulticast() {
		return true
	}

