		if err := client.DoTimeout(req, resp, 10*time.Second); err != nil {
			return err
		}

		statusCode := resp.StatusCode()
		if statusCode != fasthttp.StatusMovedPermanently &&
			statusCode != fasthttp.StatusFound &&
			statusCode != fasthttp.StatusSeeOther &&
			statusCode != fasthttp.StatusTemporaryRedirect &&
			statusCode != fasthttp.StatusPermanentRedirect {
			return nil
		}

		location := resp.Header.Peek("Location")
		if len(location) == 0 {
			return nil
		}

		redirectURL := string(location)

		// Handle relative URLs
		if !strings.HasPrefix(redirectURL, "http://") && !strings.HasPrefix(redirectURL, "https://") {
			baseURL := string(req.URI().FullURI())
			base, err := url.Parse(baseURL)
			if err != nil {
				return fmt.Errorf("failed to parse base URL: %v", err)
			}
			ref, err := url.Parse(redirectURL)
			if err != nil {
				return fmt.Errorf("failed to parse redirect URL: %v", err)
			}
			redirectURL = base.ResolveReference(ref).String()
		}

		// Validate redirect URL for SSRF
		if err := validateURL(redirectURL); err != nil {
			return fmt.Errorf("redirect blocked: %v", err)
		}

		req.SetRequestURI(redirectURL)

		// For 303, change method to GET
		if statusCode == fasthttp.StatusSeeOther {
			req.Header.SetMethod("GET")
			req.SetBody(nil)
		}
	}

	return fmt.Errorf("too many redirects")
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)

	var inTitle bool

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			err := tokenizer.Err()
			if err == io.EOF {
				return title, description, nil
			}
			return title, description, err

		case html.StartTagToken:
			tn, hasAttr := tokenizer.TagName()
			tagName := string(tn)

			if tagName == "title" {
				inTitle = true
			}

			if tagName == "meta" && hasAttr {
				var nameVal, contentVal string
				for {
					key, val, more := tokenizer.TagAttr()
					k := strings.ToLower(string(key))
					if k == "name" {
						nameVal = string(val)
					} else if k == "content" {
						contentVal = string(val)
					}
					if !more {
						break
					}
				}
				if strings.EqualFold(nameVal, "description") && description == "" {
					description = contentVal
				}
			}

		case html.TextToken:
			if inTitle {
				title += string(tokenizer.Text())
			}

		case html.EndTagToken:
			tn, _ := tokenizer.TagName()
			if string(tn) == "title" {
				inTitle = false
				title = strings.TrimSpace(title)
			}

		case html.SelfClosingTagToken:
			tn, hasAttr := tokenizer.TagName()
			tagName := string(tn)

			if tagName == "meta" && hasAttr {
				var nameVal, contentVal string
				for {
					key, val, more := tokenizer.TagAttr()
					k := strings.ToLower(string(key))
					if k == "name" {
						nameVal = string(val)
					} else if k == "content" {
						contentVal = string(val)
					}
					if !more {
						break
					}
				}
				if strings.EqualFold(nameVal, "description") && description == "" {
					description = contentVal
				}
			}
		}

		// Early exit if we have both values
		if title != "" && description != "" {
			return title, description, nil
		}
	}
}

func main() {
	requestHandler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not found", fasthttp.StatusNotFound)
		}
	}

	fmt.Println("Server starting on :8080")
	if err := fasthttp.ListenAndServe(":8080", requestHandler); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

