				if strings.EqualFold(attr.Key, "property") && strings.EqualFold(attr.Val, "og:description") {
					nameAttr = "description"
				}
			}
			if strings.EqualFold(nameAttr, "description") && description == "" {
				description = contentAttr
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return strings.TrimSpace(title), strings.TrimSpace(description)
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		resp := URLPreviewResponse{Error: "method not allowed, use POST"}
		data, _ := json.Marshal(resp)
		ctx.SetBody(data)
		return
	}

	var reqBody URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		resp := URLPreviewResponse{Error: fmt.Sprintf("invalid JSON body: %v", err)}
		data, _ := json.Marshal(resp)
		ctx.SetBody(data)
		return
	}

	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		resp := URLPreviewResponse{Error: "url field is required"}
		data, _ := json.Marshal(resp)
		ctx.SetBody(data)
		return
	}

	// Validate URL for SSRF protection
	if err := isURLSafe(reqBody.URL); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		resp := URLPreviewResponse{
			URL:   reqBody.URL,
			Error: fmt.Sprintf("URL validation failed: %v", err),
		}
		data, _ := json.Marshal(resp)
		ctx.SetBody(data)
		return
	}

	req := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(res)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	maxRedirects := 10
	if err := httpClient.DoRedirects(req, res, maxRedirects); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		resp := URLPreviewResponse{
			URL:   reqBody.URL,
			Error: fmt.Sprintf("failed to fetch URL: %v", err),
		}
		data, _ := json.Marshal(resp)
		ctx.SetBody(data)
		return
	}

	body := res.Body()
	title, description := extractTitleAndDescription(body)

	resp := URLPreviewResponse{
		Title:       title,
		Description: description,
		URL:         reqBody.URL,
	}

	data, err := json.Marshal(resp)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		errResp := URLPreviewResponse{Error: "failed to marshal response"}
		errData, _ := json.Marshal(errResp)
		ctx.SetBody(errData)
		return
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetBody(data)
}

func main() {
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.SetBodyString(`{"error":"not found"}`)
		}
	}

	fmt.Println("Server starting on :8080")
	log.Fatal(fasthttp.ListenAndServe(":8080", handler))
}

