// isHostSafe checks if the hostname resolves to a safe (non-private) IP
func isHostSafe(hostname string) ([]net.IP, error) {
	// If it's already an IP address, check directly
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private IP addresses is not allowed")
		}
		return []net.IP{ip}, nil
	}

	// Resolve the hostname
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve hostname: %v", err)
	}

	if len(ips) == 0 {
		return nil, fmt.Errorf("hostname did not resolve to any IP addresses")
	}

	var safeIPs []net.IP
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private IP addresses is not allowed")
		}
		safeIPs = append(safeIPs, ip)
	}

	return safeIPs, nil
}

// safeDial is a custom dialer that prevents connections to private IPs
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address: %v", err)
	}

	var ips []net.IP
	if ip := net.ParseIP(host); ip != nil {
		ips = []net.IP{ip}
	} else {
		resolved, err := net.LookupIP(host)
		if err != nil {
			return nil, fmt.Errorf("failed to resolve host: %v", err)
		}
		ips = resolved
	}

	// Filter to only safe IPs
	var safeIP net.IP
	for _, ip := range ips {
		if !isPrivateIP(ip) {
			safeIP = ip
			break
		}
	}

	if safeIP == nil {
		return nil, fmt.Errorf("access to private IP addresses is not allowed")
	}

	// Connect to the safe IP directly
	safeAddr := net.JoinHostPort(safeIP.String(), port)
	return net.DialTimeout("tcp", safeAddr, 10*time.Second)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusForbidden)
		return
	}

	// Extract hostname and validate it's not a private/internal address
	hostname := parsedURL.Hostname()
	if hostname == "" {
		ctx.Error("URL must contain a valid hostname", fasthttp.StatusBadRequest)
		return
	}

	// Check if host resolves to a safe IP before making the request
	if _, err := isHostSafe(hostname); err != nil {
		ctx.Error(fmt.Sprintf("Blocked: %v", err), fasthttp.StatusForbidden)
		return
	}

	// Use fasthttp.Client with safe dialer to prevent SSRF
	client := &fasthttp.Client{
		Dial:                safeDial,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	if err := client.DoTimeout(freq, res, 15*time.Second); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Handle redirects manually to check each redirect target
	maxRedirects := 10
	for i := 0; i < maxRedirects; i++ {
		statusCode := res.StatusCode()
		if statusCode != fasthttp.StatusMovedPermanently &&
			statusCode != fasthttp.StatusFound &&
			statusCode != fasthttp.StatusSeeOther &&
			statusCode != fasthttp.StatusTemporaryRedirect &&
			statusCode != fasthttp.StatusPermanentRedirect {
			break
		}

		location := string(res.Header.Peek("Location"))
		if location == "" {
			break
		}

		// Parse the redirect URL
		redirectURL, err := url.Parse(location)
		if err != nil {
			ctx.Error("Invalid redirect URL", fasthttp.StatusBadGateway)
			return
		}

		// Resolve relative URLs
		if !redirectURL.IsAbs() {
			redirectURL = parsedURL.ResolveReference(redirectURL)
