		redirectHost := redirectURL.Hostname()
		if _, err := isHostSafe(redirectHost); err != nil {
			ctx.Error(fmt.Sprintf("Blocked redirect: %v", err), fasthttp.StatusForbidden)
			return
		}

		// Follow the redirect
		parsedURL = redirectURL
		freq.SetRequestURI(redirectURL.String())
		res.Reset()

		if err := client.DoTimeout(freq, res, 15*time.Second); err != nil {
			ctx.Error(fmt.Sprintf("Failed to fetch redirected URL: %v", err), fasthttp.StatusBadGateway)
			return
		}
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
