	if h, _, err := net.SplitHostPort(hostname); err == nil {
		host = h
	}

	// Check if it's a raw IP
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
		return nil
	}

	// Resolve hostname
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname")
	}

	if len(ips) == 0 {
		return fmt.Errorf("hostname resolved to no addresses")
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
	}

	return nil
}

// safeDial creates a dialer that validates the resolved IP is not private.
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address")
	}

	// Resolve the host
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve host")
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private IP addresses is not allowed")
		}
	}

	// Connect to the first non-private IP
	for _, ip := range ips {
		if !isPrivateIP(ip) {
			address := net.JoinHostPort(ip.String(), port)
			conn, err := net.DialTimeout("tcp", address, 5*time.Second)
			if err == nil {
				return conn, nil
			}
		}
	}

	return nil, fmt.Errorf("failed to connect to host")
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Validate hostname is not empty
	if parsedURL.Hostname() == "" {
		ctx.Error("URL must contain a valid hostname", fasthttp.StatusBadRequest)
		return
	}

	// Check that the host doesn't resolve to a private IP (SSRF protection)
	if err := isHostAllowed(parsedURL.Host); err != nil {
		ctx.Error("URL not allowed: "+err.Error(), fasthttp.StatusForbidden)
		return
	}

	// Use fasthttp.Client to fetch with timeout and safe dialer
	client := &fasthttp.Client{
		Dial:                 safeDial,
		ReadTimeout:          10 * time.Second,
		WriteTimeout:         10 * time.Second,
		MaxIdleConnDuration:  10 * time.Second,
		MaxConnsPerHost:      10,
		MaxResponseBodySize:  maxResponseBodySize,
		NoDefaultUserAgentHeader: true,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Don't follow redirects automatically to prevent SSRF via redirect
	// Instead, handle redirects manually with validation
	if err := doSafeRedirects(client, freq, res, 5); err != nil {
		ctx.Error("Failed to fetch URL", fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error("Failed to parse HTML", fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// doSafeRedirects follows redirects while validating each redirect target against SSRF.
func doSafeRedirects(client *fasthttp.Client, req *fasthttp.Request, resp *fasthttp.Response, maxRedirects int) error {
	for i := 0; i <= maxRedirects; i++ {
		if err := client.Do(req, resp); err != nil {
			return err
		}

		statusCode := resp.StatusCode()
		if statusCode != fasthttp.StatusMovedPermanently &&
			statusCode != fasthttp.StatusFound &&
			statusCode != fasthttp.StatusSeeOther &&
			statusCode != fasthttp.StatusTemporaryRedirect &&
			statusCode != fasthttp.StatusPermanentRedirect {
			return nil
		}

		location := resp.Header.Peek("Location")
		if len(location) == 0 {
			return fmt.Errorf("redirect with no Location header")
		}

		redirectURL := string(location)

		// Parse and validate the redirect URL
		parsedRedirect, err := url.Parse(redirectURL)
		if err != nil {
			return fmt.Errorf("invalid redirect URL")
		}

		// Handle relative URLs
		if !parsedRedirect.IsAbs() {
			baseURL, err := url.Parse(string(req.URI().FullURI()))
			if err != nil {
				return fmt.Errorf("failed to parse base URL")
			}
			parsedRedirect = baseURL.ResolveReference(parsedRedirect)
			redirectURL = parsedRedirect.String()
		}

		// Validate scheme
		if parsedRedirect.Scheme != "http" && parsedRedirect.Scheme != "https" {
			return fmt.Errorf("redirect to non-http(s) scheme not allowed")
		}

		// Validate the redirect target is not a private IP (SSRF protection)
		if err := isHostAllowed(parsedRedirect.Host); err != nil {
			return fmt.Errorf("redirect target not allowed: %v", err)
		}

		// Update request for next redirect
		req.SetRequestURI(redirectURL)
		req.Header.SetMethod("GET")
	}

	return fmt.Errorf("too many redirects")
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	return "dummy title", "dummy description", nil
}

func main() {
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not found", fasthttp.StatusNotFound)
		}
	}

	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		panic(err)
	}
}

