		}
		if cidr.Contains(ip) {
			return true
		}
	}

	return false
}

// isHostnamePrivate checks if a hostname resolves to or represents a private IP.
func isHostnamePrivate(hostname string) bool {
	lowerHost := strings.ToLower(hostname)
	if lowerHost == "localhost" || strings.HasSuffix(lowerHost, ".local") || strings.HasSuffix(lowerHost, ".internal") {
		return true
	}

	// Check if it's a direct IP
	ip := net.ParseIP(hostname)
	if ip != nil {
		return isPrivateIP(ip)
	}

	// Also try to handle decimal IP notation (e.g., 2130706433 = 127.0.0.1)
	// This is handled by net.ParseIP for standard formats, but decimal IPs
	// might slip through - we check them via DNS resolution below

	// Resolve hostname
	ips, err := net.LookupIP(hostname)
	if err != nil {
		// If we can't resolve, block it to be safe
		return true
	}

	for _, resolvedIP := range ips {
		if isPrivateIP(resolvedIP) {
			return true
		}
	}

	return false
}

// validateURLSchemeAndFormat checks basic URL format and scheme.
func validateURLSchemeAndFormat(targetURL string) (*url.URL, error) {
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		return nil, fmt.Errorf("invalid URL format: %w", err)
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, fmt.Errorf("URL must use http or https scheme")
	}

	hostname := parsedURL.Hostname()
	if hostname == "" {
		return nil, fmt.Errorf("URL must have a hostname")
	}

	return parsedURL, nil
}

// validateURL performs full SSRF validation on a URL string.
func validateURL(targetURL string) error {
	parsedURL, err := validateURLSchemeAndFormat(targetURL)
	if err != nil {
		return err
	}

	hostname := parsedURL.Hostname()
	if isHostnamePrivate(hostname) {
		return fmt.Errorf("access to private/internal addresses is not allowed")
	}

	return nil
}

// safeDial creates a dialer that checks resolved IPs before connecting.
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address: %w", err)
	}

	// Resolve and validate IPs
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve host: %w", err)
	}

	var safeIPs []net.IP
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("connection to private IP address is not allowed")
		}
		safeIPs = append(safeIPs, ip)
	}

	if len(safeIPs) == 0 {
		return nil, fmt.Errorf("no valid addresses found")
	}

	dialer := &net.Dialer{
		Timeout: 10 * time.Second,
	}

	for _, ip := range safeIPs {
		ipAddr := ip.String()
		if ip.To4() == nil {
			ipAddr = "[" + ipAddr + "]"
		}
		conn, err := dialer.Dial("tcp", ipAddr+":"+port)
		if err == nil {
			return conn, nil
		}
	}

	return nil, fmt.Errorf("failed to connect to any resolved address")
}

