// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", fmt.Errorf("failed to parse HTML: %w", err)
	}

	var extractText func(*html.Node) string
	extractText = func(n *html.Node) string {
		if n == nil {
			return ""
		}
		var sb strings.Builder
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			if c.Type == html.TextNode {
				sb.WriteString(c.Data)
			} else {
				sb.WriteString(extractText(c))
			}
		}
		return sb.String()
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				title = strings.TrimSpace(extractText(n))
			}
			if n.Data == "meta" {
				var nameAttr, contentAttr string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						nameAttr = strings.ToLower(attr.Val)
					case "content":
						contentAttr = attr.Val
					case "property":
						nameAttr = strings.ToLower(attr.Val)
					}
				}
				if nameAttr == "description" && description == "" {
					description = strings.TrimSpace(contentAttr)
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description, nil
}

