		}
	}
	return ""
}

func extractMetaDescription(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "meta" {
		isDescription := false
		content := ""
		for _, attr := range n.Attr {
			if (strings.EqualFold(attr.Key, "name") || strings.EqualFold(attr.Key, "property")) &&
