		return true
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return true
		}
	}

	return false
}

// safeDial is a custom dialer that validates the resolved IP is not private before connecting.
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address: %v", err)
	}

	// Check if it's already an IP
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private IP addresses is not allowed")
		}
		return net.DialTimeout("tcp", addr, 5*time.Second)
	}

	// Resolve the host
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve host: %v", err)
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private IP addresses is not allowed")
		}
	}

	// Connect using the first valid non-private IP
	for _, ip := range ips {
		resolvedAddr := net.JoinHostPort(ip.String(), port)
		conn, err := net.DialTimeout("tcp", resolvedAddr, 5*time.Second)
		if err == nil {
			return conn, nil
		}
	}

	return nil, fmt.Errorf("failed to connect to any resolved address")
}

