		}

		if safeIP == nil {
			return nil, fmt.Errorf("all resolved IPs for %s are private/internal", host)
		}

		// Connect using the validated IP directly to prevent DNS rebinding
		dialer := &net.Dialer{Timeout: 10 * time.Second}
		return dialer.Dial("tcp", net.JoinHostPort(safeIP.String(), port))
	},
	MaxResponseBodySize: 10 * 1024 * 1024,
}

func extractTitleAndDescription(htmlBody string) (string, string) {
	doc, err := html.Parse(strings.NewReader(htmlBody))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil {
				title = n.FirstChild.Data
			}
		}

		if n.Type == html.ElementNode && n.Data == "meta" {
			var nameAttr, contentAttr string
			for _, attr := range n.Attr {
				if strings.EqualFold(attr.Key, "name") {
					nameAttr = attr.Val
				}
				if strings.EqualFold(attr.Key, "content") {
					contentAttr = attr.Val
				}
			}
			if strings.EqualFold(nameAttr, "description") {
				description = contentAttr
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		resp := URLPreviewResponse{Error: "method not allowed, use POST"}
		data, _ := json.Marshal(resp)
		ctx.SetBody(data)
		return
	}

	var reqBody URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		resp := URLPreviewResponse{Error: fmt.Sprintf("invalid JSON body: %v", err)}
		data, _ := json.Marshal(resp)
		ctx.SetBody(data)
		return
	}

	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		resp := URLPreviewResponse{Error: "url field is required"}
		data, _ := json.Marshal(resp)
		ctx.SetBody(data)
		return
	}

	// Validate URL scheme and host
	if _, err := validateURLSchemeAndHost(reqBody.URL); err != nil {
		ctx.SetStatusCode(fasthttp.StatusForbidden)
		resp := URLPreviewResponse{
			URL:   reqBody.URL,
			Error: fmt.Sprintf("URL validation failed: %v", err),
		}
		data, _ := json.Marshal(resp)
		ctx.SetBody(data)
		return
	}

	req := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(res)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	if err := httpClient.DoRedirects(req, res, 10); err != nil {
		// Check if the error is due to SSRF protection
		errStr := err.Error()
		if strings.Contains(errStr, "private") || strings.Contains(errStr, "internal") || strings.Contains(errStr, "not allowed") {
			ctx.SetStatusCode(fasthttp.StatusForbidden)
			resp := URLPreviewResponse{
				URL:   reqBody.URL,
				Error: fmt.Sprintf("URL validation failed: %v", err),
			}
			data, _ := json.Marshal(resp)
			ctx.SetBody(data)
			return
		}

		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		resp := URLPreviewResponse{
			URL:   reqBody.URL,
			Error: fmt.Sprintf("failed to fetch URL: %v", err),
		}
		data, _ := json.Marshal(resp)
		ctx.SetBody(data)
		return
	}

	body := string(res.Body())
	title, description := extractTitleAndDescription(body)

	resp := URLPreviewResponse{
		Title:       title,
		Description: description,
		URL:         reqBody.URL,
	}

	data, err := json.Marshal(resp)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		errResp := URLPreviewResponse{Error: "failed to marshal response"}
		errData, _ := json.Marshal(errResp)
		ctx.SetBody(errData)
		return
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetBody(data)
}

func main() {
	requestHandler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.SetBodyString(`{"error":"not found"}`)
		}
	}

	fmt.Println("Server starting on :8080")
	if err := fasthttp.ListenAndServe(":8080", requestHandler); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

