// isPrivateIP checks if an IP address is in a private/reserved range.
func isPrivateIP(ip net.IP) bool {
	privateRanges := []struct {
		network *net.IPNet
	}{
		{parseCIDR("10.0.0.0/8")},
		{parseCIDR("172.16.0.0/12")},
		{parseCIDR("192.168.0.0/16")},
		{parseCIDR("127.0.0.0/8")},
		{parseCIDR("0.0.0.0/8")},
		{parseCIDR("169.254.0.0/16")},
		{parseCIDR("224.0.0.0/4")},
		{parseCIDR("240.0.0.0/4")},
		{parseCIDR("::1/128")},
		{parseCIDR("::/128")},
		{parseCIDR("fc00::/7")},
		{parseCIDR("fe80::/10")},
		{parseCIDR("ff00::/8")},
		{parseCIDR("100.64.0.0/10")},
		{parseCIDR("198.18.0.0/15")},
		{parseCIDR("192.0.0.0/24")},
		{parseCIDR("192.0.2.0/24")},
		{parseCIDR("198.51.100.0/24")},
		{parseCIDR("203.0.113.0/24")},
	}

	for _, r := range privateRanges {
		if r.network != nil && r.network.Contains(ip) {
			return true
		}
	}
	return false
}

func parseCIDR(cidr string) *net.IPNet {
	_, network, err := net.ParseCIDR(cidr)
	if err != nil {
		return nil
	}
	return network
}

// validateURL checks that the URL is safe to fetch (not targeting internal resources).
func validateURL(targetURL string) error {
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		return fmt.Errorf("invalid URL format")
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("URL must use http or https scheme")
	}

	hostname := parsedURL.Hostname()
	if hostname == "" {
		return fmt.Errorf("URL must have a hostname")
	}

	// Block localhost variants
	lowerHost := strings.ToLower(hostname)
	if lowerHost == "localhost" || lowerHost == "localhost." {
		return fmt.Errorf("access to localhost is not allowed")
	}

	// Check for decimal/octal/hex IP representations
	// Try to parse as IP first
	ip := net.ParseIP(hostname)
	if ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private/internal IP addresses is not allowed")
		}
		return nil
	}

	// Resolve hostname to IP addresses
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %v", err)
	}

	if len(ips) == 0 {
		return fmt.Errorf("hostname resolved to no addresses")
	}

	for _, resolvedIP := range ips {
		if isPrivateIP(resolvedIP) {
			return fmt.Errorf("hostname resolves to a private/internal IP address")
		}
	}

	return nil
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL for SSRF
	if err := validateURL(targetURL); err != nil {
		resp := PreviewResponse{Error: err.Error()}
		ctx.SetContentType("application/json; charset=utf-8")
		ctx.SetStatusCode(fasthttp.StatusForbidden)
		json.NewEncoder(ctx).Encode(resp)
		return
	}

	// Custom dialer that checks resolved IPs before connecting
	safeDial := func(addr string) (net.Conn, error) {
		host, port, err := net.SplitHostPort(addr)
		if err != nil {
			return nil, fmt.Errorf("invalid address: %v", err)
		}

		// Resolve the host
		ips, err := net.LookupIP(host)
		if err != nil {
			return nil, fmt.Errorf("failed to resolve host: %v", err)
		}

		for _, ip := range ips {
			if isPrivateIP(ip) {
				return nil, fmt.Errorf("connection to private IP address is not allowed")
			}
		}

		// Connect to the first valid IP
		for _, ip := range ips {
			addr := net.JoinHostPort(ip.String(), port)
			conn, err := net.DialTimeout("tcp", addr, 10*time.Second)
			if err == nil {
				return conn, nil
			}
		}
		return nil, fmt.Errorf("failed to connect to any resolved address")
	}

	// Use fasthttp.Client to fetch with timeout and safe dialer
	client := &fasthttp.Client{
		Dial:                safeDial,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 10
	err := client.DoRedirects(freq, res, maxRedirectCounts)
	if err != nil {
		errMsg := err.Error()
		if strings.Contains(errMsg, "private IP") || strings.Contains(errMsg, "not allowed") {
			resp := PreviewResponse{Error: "access to private/internal addresses is not allowed"}
			ctx.SetContentType("application/json; charset=utf-8")
			ctx.SetStatusCode(fasthttp.StatusForbidden)
			json.NewEncoder(ctx).Encode(resp)
			return
		}
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Validate redirect target - check the final URL after redirects
	finalURI := res.Header.Peek("Location")
	if len(finalURI) > 0 {
		if err := validateURL(string(finalURI)); err != nil {
			resp := PreviewResponse{Error: "redirect target is not allowed"}
			ctx.SetContentType("application/json; charset=utf-8")
			ctx.SetStatusCode(fasthttp.StatusForbidden)
			json.NewEncoder(ctx).Encode(resp)
			return
		}
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)

	var inTitle bool

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			err := tokenizer.Err()
			if err == io.EOF {
				return title, description, nil
			}
			return title, description, err

		case html.StartTagToken:
			tn, hasAttr := tokenizer.TagName()
			tagName := string(tn)

			if tagName == "title" {
				inTitle = true
			}

			if tagName == "meta" && hasAttr {
				var nameVal, contentVal string
				for {
					key, val, more := tokenizer.TagAttr()
					k := strings.ToLower(string(key))
					if k == "name" {
						nameVal = string(val)
					} else if k == "content" {
						contentVal = string(val)
					}
					if !more {
						break
					}
				}
				if strings.EqualFold(nameVal, "description") && description == "" {
					description = contentVal
				}
			}

		case html.TextToken:
			if inTitle {
				title += string(tokenizer.Text())
			}

		case html.EndTagToken:
			tn, _ := tokenizer.TagName()
			if string(tn) == "title" {
				inTitle = false
				title = strings.TrimSpace(title)
			}

		case html.SelfClosingTagToken:
			tn, hasAttr := tokenizer.TagName()
			tagName := string(tn)

			if tagName == "meta" && hasAttr {
				var nameVal, contentVal string
				for {
					key, val, more := tokenizer.TagAttr()
					k := strings.ToLower(string(key))
					if k == "name" {
						nameVal = string(val)
					} else if k == "content" {
						contentVal = string(val)
					}
					if !more {
						break
					}
				}
				if strings.EqualFold(nameVal, "description") && description == "" {
					description = contentVal
				}
			}
		}

		// Early exit if we have both
		if title != "" && description != "" {
			return title, description, nil
		}
	}
}

func main() {
	fmt.Println("Starting server on :8080")
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

