	"time"

	"github.com/valyala/fasthttp"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

const maxResponseBodySize = 5 * 1024 * 1024 // 5 MB

// isPrivateIP checks if an IP address is in a private/reserved range.
func isPrivateIP(ip net.IP) bool {
	privateRanges := []struct {
		network *net.IPNet
	}{
		{parseCIDR("127.0.0.0/8")},
		{parseCIDR("10.0.0.0/8")},
		{parseCIDR("172.16.0.0/12")},
		{parseCIDR("192.168.0.0/16")},
		{parseCIDR("169.254.0.0/16")},
		{parseCIDR("0.0.0.0/8")},
		{parseCIDR("100.64.0.0/10")},
		{parseCIDR("192.0.0.0/24")},
		{parseCIDR("192.0.2.0/24")},
		{parseCIDR("198.18.0.0/15")},
		{parseCIDR("198.51.100.0/24")},
		{parseCIDR("203.0.113.0/24")},
		{parseCIDR("224.0.0.0/4")},
		{parseCIDR("240.0.0.0/4")},
		{parseCIDR("255.255.255.255/32")},
		// IPv6
		{parseCIDR("::1/128")},
		{parseCIDR("fc00::/7")},
		{parseCIDR("fe80::/10")},
		{parseCIDR("::ffff:127.0.0.0/104")},
		{parseCIDR("::ffff:10.0.0.0/104")},
		{parseCIDR("::ffff:172.16.0.0/108")},
		{parseCIDR("::ffff:192.168.0.0/112")},
		{parseCIDR("::/128")},
	}

	for _, r := range privateRanges {
		if r.network.Contains(ip) {
			return true
		}
	}
	return false
}

func parseCIDR(cidr string) *net.IPNet {
	_, network, err := net.ParseCIDR(cidr)
	if err != nil {
		panic(fmt.Sprintf("invalid CIDR: %s", cidr))
	}
	return network
}

// validateAndResolveURL checks that the URL's host does not resolve to a private IP.
func validateAndResolveURL(targetURL string) (string, error) {
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		return "", fmt.Errorf("invalid URL format")
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return "", fmt.Errorf("URL must use http or https scheme")
	}

	hostname := parsedURL.Hostname()
	if hostname == "" {
		return "", fmt.Errorf("URL must have a valid hostname")
	}

	// Check if hostname is an IP address directly
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip) {
			return "", fmt.Errorf("access to private/internal addresses is not allowed")
		}
		return targetURL, nil
	}

	// Resolve hostname to IP addresses
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return "", fmt.Errorf("failed to resolve hostname: %v", err)
	}

	if len(ips) == 0 {
		return "", fmt.Errorf("hostname did not resolve to any IP address")
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return "", fmt.Errorf("access to private/internal addresses is not allowed")
		}
	}

	return targetURL, nil
}

// safeDial creates a dialer that validates resolved IPs are not private.
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address: %v", err)
	}

	// Resolve the host
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, fmt.Errorf("DNS resolution failed: %v", err)
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private/internal addresses is not allowed")
		}
	}

	// Connect to the first valid public IP
	for _, ip := range ips {
		if !isPrivateIP(ip) {
			address := net.JoinHostPort(ip.String(), port)
			conn, err := net.DialTimeout("tcp", address, 5*time.Second)
			if err == nil {
				// Verify the connected remote address is still safe
				remoteAddr := conn.RemoteAddr().(*net.TCPAddr)
				if isPrivateIP(remoteAddr.IP) {
					conn.Close()
					return nil, fmt.Errorf("access to private/internal addresses is not allowed")
				}
				return conn, nil
			}
		}
	}

	return nil, fmt.Errorf("failed to connect to any resolved address")
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme and check for SSRF
	validatedURL, err := validateAndResolveURL(targetURL)
	if err != nil {
		ctx.Error(err.Error(), fasthttp.StatusBadRequest)
		return
	}

	// Use fasthttp.Client with safe dialer to prevent SSRF via redirects
	client := &fasthttp.Client{
		Dial:                safeDial,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		MaxResponseBodySize: maxResponseBodySize,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(validatedURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 5
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	return "dummy title", "dummy description", nil
}

func main() {
	requestHandler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not found", fasthttp.StatusNotFound)
		}
	}

	fmt.Println("Server starting on :8080")
	if err := fasthttp.ListenAndServe(":8080", requestHandler); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

