	"golang.org/x/net/html"
)

type URLRequest struct {
	URL string `json:"url"`
}

type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	URL         string `json:"url"`
}

type ErrorResponse struct {
	Error string `json:"error"`
}

var httpClient = &fasthttp.Client{
	Dial:            fasthttp.DialDualStack,
	ReadTimeout:     3 * time.Second,
	WriteTimeout:    3 * time.Second,
	MaxConnsPerHost: 100,
}

func extractTitleAndDescription(htmlBody string) (string, string) {
	doc, err := html.Parse(strings.NewReader(htmlBody))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil {
				title = n.FirstChild.Data
			}
		}

		if n.Type == html.ElementNode && n.Data == "meta" {
			var nameAttr, contentAttr string
			for _, attr := range n.Attr {
				if strings.EqualFold(attr.Key, "name") {
					nameAttr = attr.Val
				}
				if strings.EqualFold(attr.Key, "content") {
					contentAttr = attr.Val
				}
			}
			if strings.EqualFold(nameAttr, "description") {
				description = contentAttr
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		resp, _ := json.Marshal(ErrorResponse{Error: "method not allowed"})
		ctx.SetBody(resp)
		return
	}

	var reqBody URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		resp, _ := json.Marshal(ErrorResponse{Error: "invalid JSON body"})
		ctx.SetBody(resp)
		return
	}

	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		resp, _ := json.Marshal(ErrorResponse{Error: "url field is required"})
		ctx.SetBody(resp)
		return
	}

	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(res)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.SetTimeout(3 * time.Second)

	if err := httpClient.DoRedirects(req, res, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		resp, _ := json.Marshal(ErrorResponse{Error: fmt.Sprintf("failed to fetch URL: %s", err.Error())})
		ctx.SetBody(resp)
		return
	}

	body := string(res.Body())
	title, description := extractTitleAndDescription(body)

	preview := URLPreviewResponse{
		Title:       title,
		Description: description,
		URL:         reqBody.URL,
	}

	respJSON, err := json.Marshal(preview)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		resp, _ := json.Marshal(ErrorResponse{Error: "failed to marshal response"})
		ctx.SetBody(resp)
		return
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetBody(respJSON)
}

func main() {
	requestHandler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
		}
	}

	fmt.Println("Server starting on :8080")
	if err := fasthttp.ListenAndServe(":8080", requestHandler); err != nil {
		fmt.Printf("Error starting server: %s\n", err)
	}
}

