// parseDecimalIP tries to parse a decimal IP representation like "2130706433" -> 127.0.0.1
func parseDecimalIP(host string) net.IP {
	n := new(big.Int)
	_, ok := n.SetString(host, 10)
	if !ok {
		return nil
	}
	// Check if it's a valid 32-bit number
	if n.Sign() < 0 || n.BitLen() > 32 {
		return nil
	}
	ipInt := n.Int64()
	ip := net.IPv4(byte(ipInt>>24), byte(ipInt>>16), byte(ipInt>>8), byte(ipInt))
	return ip
}

// validateURLForSSRF checks if the URL is safe to fetch (not targeting internal resources)
func validateURLForSSRF(targetURL string) (string, error) {
	parsedURL, err := url.Parse(targetURL)
	if err != nil {
		return "", fmt.Errorf("invalid URL format")
	}

	scheme := strings.ToLower(parsedURL.Scheme)
	if scheme != "http" && scheme != "https" {
		return "", fmt.Errorf("only http and https schemes are allowed")
	}

	hostname := parsedURL.Hostname()
	if hostname == "" {
		return "", fmt.Errorf("URL must have a hostname")
	}

	// Block common internal hostnames
	lowerHost := strings.ToLower(hostname)
	if lowerHost == "localhost" || strings.HasSuffix(lowerHost, ".local") || strings.HasSuffix(lowerHost, ".internal") {
		return "", fmt.Errorf("access to internal hosts is not allowed")
	}

	// Check for decimal IP notation (e.g., 2130706433 = 127.0.0.1)
	if decIP := parseDecimalIP(hostname); decIP != nil {
		if isPrivateIP(decIP) {
			return "", fmt.Errorf("access to private IP addresses is not allowed")
		}
	}

	// Check if hostname is a direct IP address
	ip := net.ParseIP(hostname)
	if ip != nil {
		if isPrivateIP(ip) {
			return "", fmt.Errorf("access to private IP addresses is not allowed")
		}
		return targetURL, nil
	}

	// Resolve hostname and check all IPs - pin to the first safe IP
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return "", fmt.Errorf("failed to resolve hostname: %v", err)
	}

	if len(ips) == 0 {
		return "", fmt.Errorf("hostname resolved to no addresses")
	}

	for _, resolvedIP := range ips {
		if isPrivateIP(resolvedIP) {
			return "", fmt.Errorf("hostname resolves to a private IP address")
		}
	}

	return targetURL, nil
}

