package main

import (
	"encoding/json"
	"fmt"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

type URLRequest struct {
	URL string `json:"url"`
}

type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	URL         string `json:"url"`
}

type ErrorResponse struct {
	Error string `json:"error"`
}

var client = &fasthttp.Client{
	Dial:                fasthttp.DialDualStack,
	MaxResponseBodySize: 10 * 1024 * 1024,
	ReadTimeout:         3 * time.Second,
	WriteTimeout:        3 * time.Second,
}

func extractTitle(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "title" {
		if n.FirstChild != nil {
			return strings.TrimSpace(n.FirstChild.Data)
		}
		return ""
	}
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result := extractTitle(c)
		if result != "" {
			return result
		}
	}
	return ""
}

func extractMetaDescription(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "meta" {
		isDescription := false
		content := ""
		for _, attr := range n.Attr {
			if strings.EqualFold(attr.Key, "name") && strings.EqualFold(attr.Val, "description") {
				isDescription = true
			}
			if strings.EqualFold(attr.Key, "content") {
				content = attr.Val
			}
		}
		if isDescription {
			return content
		}
	}
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result := extractMetaDescription(c)
		if result != "" {
			return result
		}
	}
	return ""
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	var reqBody URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		resp, _ := json.Marshal(ErrorResponse{Error: "invalid JSON body"})
		ctx.SetBody(resp)
		return
	}

	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		resp, _ := json.Marshal(ErrorResponse{Error: "url field is required"})
		ctx.SetBody(resp)
		return
	}

	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(res)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	if err := client.DoRedirects(req, res, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		resp, _ := json.Marshal(ErrorResponse{Error: fmt.Sprintf("failed to fetch URL: %s", err.Error())})
		ctx.SetBody(resp)
		return
	}

	body := res.Body()
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		resp, _ := json.Marshal(ErrorResponse{Error: fmt.Sprintf("failed to parse HTML: %s", err.Error())})
		ctx.SetBody(resp)
		return
	}

	title := extractTitle(doc)
	description := extractMetaDescription(doc)

	preview := URLPreviewResponse{
		Title:       title,
		Description: description,
		URL:         reqBody.URL,
	}

	resp, _ := json.Marshal(preview)
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetBody(resp)
}

func main() {
	fmt.Println("Starting server on :8080")
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		fmt.Printf("Error starting server: %s\n", err)
	}
}

