			URL:   reqBody.URL,
			Error: fmt.Sprintf("URL validation failed: %v", err),
		}
		data, _ := json.Marshal(resp)
		ctx.SetBody(data)
		return
	}

	req := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(res)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	if err := httpClient.DoRedirects(req, res, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		resp := URLPreviewResponse{
			URL:   reqBody.URL,
			Error: fmt.Sprintf("failed to fetch URL: %v", err),
		}
		data, _ := json.Marshal(resp)
		ctx.SetBody(data)
		return
	}

	body := res.Body()
	title, description := extractTitleAndDescription(body)

	resp := URLPreviewResponse{
		Title:       title,
		Description: description,
		URL:         reqBody.URL,
	}

	data, err := json.Marshal(resp)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		errResp := URLPreviewResponse{Error: "failed to marshal response"}
		errData, _ := json.Marshal(errResp)
		ctx.SetBody(errData)
		return
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetBody(data)
}

func main() {
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.SetBodyString("not found")
		}
	}

	log.Println("Starting server on :8080")
	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

